const input = $input.first().json;
const body = input.body ?? input;
const record = body.record ?? body.demand ?? body;
const oldRecord = body.old_record ?? body.oldRecord ?? null;
const eventType = body.type ?? body.event ?? body.action ?? 'crm.event';
const now = new Date().toISOString();

const statusChanged = oldRecord?.status && record?.status && oldRecord.status !== record.status;
const title = statusChanged
  ? `Demanda atualizada: ${record.title ?? record.client ?? record.id}`
  : `Evento CRM: ${record.title ?? record.client ?? record.id ?? eventType}`;
const message = statusChanged
  ? `Status alterado de ${oldRecord.status} para ${record.status}.`
  : `Evento ${eventType} recebido pelo n8n.`;

return [{
  json: {
    ok: true,
    receivedAt: now,
    eventType,
    record,
    oldRecord,
    notification: {
      title,
      message,
      type: statusChanged ? 'info' : 'success',
      targetUserId: record.assignee_id ?? record.assigneeId ?? null,
      taskId: record.id ?? null
    },
    next: [
      'Insert notification in Supabase when service-role credential is connected',
      'Send optional ops alert when status enters Em Revisao or Concluido'
    ]
  }
}];
